#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return y[0] - x[0];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int K;
        scanf("%d", &K);
        int candidates[K][2];
        for (int i = 0; i < K; i++) {
            scanf("%d %d", &candidates[i][0], &candidates[i][1]);
        }
        qsort(candidates, K, sizeof(candidates[0]), compare);
        int N;
        scanf("%d", &N);
        int orders[N][2];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &orders[i][0], &orders[i][1]);
        }
        int totalCost = 0;
        int assigned[K];
        for (int i = 0; i < K; i++) {
            assigned[i] = 0;
        }
        for (int i = 0; i < N; i++) {
            int orderTime = orders[i][0] * 1.0 / candidates[0][0];
            if (orderTime > orders[i][1]) {
                printf("-1\n");
                goto nextTest;
            }
            for (int j = 0; j < K; j++) {
                if (candidates[j][0] * orders[i][1] >= orders[i][0]) {
                    assigned[j] = 1;
                    totalCost += candidates[j][1];
                    break;
                }
            }
        }
        printf("%d\n", totalCost);
        nextTest:;
    }
    return 0;
}

