using namespace std;

struct Candidate {
    int speed;
    int salary;
};

bool compare(const Candidate &a, const Candidate &b) {
    return a.speed > b.speed;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int K;
        cin >> K;
        Candidate candidates[K];
        for (int i = 0; i < K; i++) {
            cin >> candidates[i].speed >> candidates[i].salary;
        }
        sort(candidates, candidates + K, compare);
        int N;
        cin >> N;
        int orders[N][2];
        for (int i = 0; i < N; i++) {
            cin >> orders[i][0] >> orders[i][1];
        }
        int totalCost = 0;
        bool assigned[K];
        for (int i = 0; i < K; i++) {
            assigned[i] = false;
        }
        for (int i = 0; i < N; i++) {
            double orderTime = orders[i][0] * 1.0 / candidates[0].speed;
            if (orderTime > orders[i][1]) {
                cout << -1 << endl;
                goto nextTest;
            }
            for (int j = 0; j < K; j++) {
                if (candidates[j].speed * orders[i][1] >= orders[i][0]) {
                    assigned[j] = true;
                    totalCost += candidates[j].salary;
                    break;
                }
            }
        }
        cout << totalCost << endl;
        nextTest:;
    }
    return 0;
}

