import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int K = scanner.nextInt();
            int[][] candidates = new int[K][2];
            for (int i = 0; i < K; i++) {
                candidates[i][0] = scanner.nextInt();
                candidates[i][1] = scanner.nextInt();
            }
            Arrays.sort(candidates, (a, b) -> b[0] - a[0]);
            int N = scanner.nextInt();
            int[][] orders = new int[N][2];
            for (int i = 0; i < N; i++) {
                orders[i][0] = scanner.nextInt();
                orders[i][1] = scanner.nextInt();
            }
            int totalCost = 0;
            boolean[] assigned = new boolean[K];
            for (int i = 0; i < K; i++) {
                assigned[i] = false;
            }
            for (int i = 0; i < N; i++) {
                double orderTime = orders[i][0] * 1.0 / candidates[0][0];
                if (orderTime > orders[i][1]) {
                    System.out.println(-1);
                    continue;
                }
                for (int j = 0; j < K; j++) {
                    if (candidates[j][0] * orders[i][1] >= orders[i][0]) {
                        assigned[j] = true;
                        totalCost += candidates[j][1];
                        break;
                    }
                }
            }
            System.out.println(totalCost);
        }
    }
}

